export const portalMarkup = "<a class=\"skip-link\" href=\"#portal-main\">Skip to member content</a>\n\n    <div class=\"portal-shell\">\n      <section id=\"auth-screen\" class=\"portal-auth-screen\">\n        <div class=\"auth-layout portal-surface\">\n          <div class=\"auth-brand-panel\">\n            <a href=\"/\" class=\"back-link\">\n              <span aria-hidden=\"true\">&larr;</span>\n              Back to main site\n            </a>\n\n            <div class=\"portal-chip\">BLFSC private access</div>\n            <img src=\"/images/blfsc-logo.png\" alt=\"BLFSC club logo\" class=\"auth-logo\" />\n            <h1 class=\"brand-font auth-title\">Members only. Secure by default.</h1>\n            <p class=\"auth-lead\">\n              Sign in to access members-only merch, club updates, profile settings, and private chat\n              in one place.\n            </p>\n\n            <div class=\"auth-points\">\n              <article class=\"auth-point\">\n                <strong>Members-only merch</strong>\n                <p>Shop live club gear and place orders without leaving the portal.</p>\n              </article>\n              <article class=\"auth-point\">\n                <strong>Approved access only</strong>\n                <p>Access stays with verified member accounts so the portal stays private.</p>\n              </article>\n              <article class=\"auth-point\">\n                <strong>Club updates</strong>\n                <p>\n                  Keep your contact details current and stay in the loop on rides, drops, and\n                  notices.\n                </p>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"auth-form-panel\">\n            <div class=\"portal-chip portal-chip-alt\">Restricted portal</div>\n            <h2 class=\"brand-font auth-form-title\">Enter the members area</h2>\n            <p class=\"auth-form-copy\">\n              Use your approved member account to sign in and get straight to the members area.\n            </p>\n\n            <div id=\"auth-message\" class=\"portal-alert hidden\" aria-live=\"polite\"></div>\n\n            <form id=\"signin-form\" class=\"stack-form\">\n              <label class=\"field\" for=\"email\">\n                <span class=\"field-label\">Member email</span>\n                <input\n                  id=\"email\"\n                  name=\"email\"\n                  class=\"input\"\n                  type=\"email\"\n                  autocomplete=\"email username\"\n                  placeholder=\"name@example.com\"\n                  required\n                />\n              </label>\n\n              <label class=\"field\" for=\"password\">\n                <span class=\"field-label\">Password</span>\n                <input\n                  id=\"password\"\n                  name=\"password\"\n                  class=\"input\"\n                  type=\"password\"\n                  autocomplete=\"current-password\"\n                  placeholder=\"Enter password\"\n                  required\n                />\n              </label>\n              <button id=\"signin-btn\" class=\"button button-primary button-full\" type=\"submit\">\n                Access members area\n              </button>\n            </form>\n\n            <div class=\"auth-help\">\n              Forgot your password? Use the recovery link sent to your email, then come back here\n              and save your new password in Account. Need access?\n              <a href=\"/contact\">Contact the club</a>.\n            </div>\n          </div>\n        </div>\n      </section>\n\n      <section id=\"member-app\" class=\"portal-app hidden\">\n        <header class=\"portal-header\">\n          <div class=\"portal-header-inner\">\n            <a class=\"brand portal-brand\" href=\"/\" aria-label=\"BLFSC main site\">\n              <img src=\"/images/blfsc-logo.png\" alt=\"BLFSC club logo\" />\n              <span>\n                <strong>BLFSC</strong>\n                <em>Members Portal</em>\n              </span>\n            </a>\n\n            <div class=\"portal-header-summary\">\n              <div class=\"portal-pill\">\n                <span>Signed in as</span>\n                <strong id=\"member-email-display\">Member</strong>\n              </div>\n              <div class=\"portal-pill\">\n                <span>Cart total</span>\n                <strong id=\"cart-total-summary\">$0.00</strong>\n              </div>\n            </div>\n\n            <div class=\"portal-header-actions\">\n              <a href=\"/\" class=\"button button-secondary\">Main site</a>\n              <button\n                id=\"toggle-cart\"\n                class=\"button button-secondary portal-cart-button\"\n                type=\"button\"\n              >\n                Cart\n                <span id=\"cart-badge\" class=\"cart-badge hidden\">0</span>\n              </button>\n              <button id=\"signout-btn\" class=\"button button-danger\" type=\"button\">Sign out</button>\n            </div>\n          </div>\n        </header>\n\n        <main id=\"portal-main\" class=\"portal-main\">\n          <section class=\"portal-hero portal-surface\" data-reveal>\n            <div>\n              <p class=\"eyebrow\">Members merchandise workspace</p>\n              <h2 class=\"brand-font\">\n                Live products, secure orders, one private place to run the drop.\n              </h2>\n              <p class=\"portal-copy\">\n                This is the private side of BLFSC. Shop the current drop, update your details, and\n                keep on top of club notices in one clean members area.\n              </p>\n            </div>\n\n            <div class=\"portal-stats\">\n              <article class=\"portal-stat\">\n                <span>Products live</span>\n                <strong id=\"products-count\">0</strong>\n              </article>\n              <article class=\"portal-stat\">\n                <span>Items in cart</span>\n                <strong id=\"cart-count-inline\">0</strong>\n              </article>\n              <article class=\"portal-stat\">\n                <span>Portal access</span>\n                <strong>Protected</strong>\n              </article>\n            </div>\n          </section>\n\n          <nav class=\"portal-tabs\" aria-label=\"Member sections\">\n            <button class=\"portal-tab is-active\" type=\"button\" data-portal-tab=\"shop\">Shop</button>\n            <button class=\"portal-tab\" type=\"button\" data-portal-tab=\"account\">Account</button>\n            <button class=\"portal-tab\" type=\"button\" data-portal-tab=\"chat\">Chat</button>\n            <button\n              id=\"admin-tab\"\n              class=\"portal-tab is-locked\"\n              type=\"button\"\n              data-portal-tab=\"admin\"\n              aria-disabled=\"true\"\n              title=\"Admin access required\"\n            >\n              Admin\n            </button>\n          </nav>\n          <div\n            id=\"admin-access-banner\"\n            class=\"portal-lock-note portal-admin-access-note hidden\"\n          ></div>\n\n          <section id=\"pane-shop\" class=\"portal-pane is-active\" data-reveal>\n            <div class=\"portal-pane-grid shop-layout\">\n              <section class=\"portal-catalog\">\n                <div class=\"portal-section-head\" data-reveal>\n                  <div>\n                    <p class=\"eyebrow\">Current drop</p>\n                    <h3 class=\"brand-font\">Available merchandise</h3>\n                  </div>\n                  <p class=\"portal-section-copy\">\n                    Browse live products, filter by category, and send your order from the same\n                    private workspace.\n                  </p>\n                </div>\n\n                <div\n                  class=\"shop-category-tabs\"\n                  id=\"shop-category-tabs\"\n                  aria-label=\"Merchandise categories\"\n                ></div>\n                <p id=\"shop-summary\" class=\"portal-shop-summary\">Loading merchandise...</p>\n\n                <div id=\"products-loading\" class=\"portal-state portal-surface\" data-reveal>\n                  Loading merchandise...\n                </div>\n\n                <div id=\"products-empty\" class=\"portal-state portal-surface hidden\" data-reveal>\n                  No merch is live right now. Check back soon for the next drop.\n                </div>\n\n                <div id=\"product-grid\" class=\"portal-product-grid hidden\"></div>\n              </section>\n\n              <aside class=\"portal-sidebar\">\n                <section class=\"portal-card portal-surface\" data-reveal>\n                  <div class=\"portal-card-head\">\n                    <p class=\"eyebrow\">Member checklist</p>\n                    <h3 class=\"brand-font\">Before you submit</h3>\n                  </div>\n                  <ul class=\"portal-checklist\">\n                    <li>Confirm sizes before adding clothing items to the cart.</li>\n                    <li>Use notes for pickup, delivery, or chapter-specific instructions.</li>\n                    <li>\n                      Reset your password inside the Account tab after a Supabase recovery email.\n                    </li>\n                  </ul>\n                </section>\n\n                <section class=\"portal-card portal-surface\" data-reveal>\n                  <div class=\"portal-card-head\">\n                    <p class=\"eyebrow\">Your history</p>\n                    <h3 class=\"brand-font\">Recent orders</h3>\n                  </div>\n                  <p class=\"portal-card-copy portal-card-copy-tight\">\n                    Submissions stay on your account so you can track club fulfillment status.\n                  </p>\n                  <button\n                    id=\"refresh-member-orders-btn\"\n                    class=\"button button-secondary button-small\"\n                    type=\"button\"\n                  >\n                    Refresh list\n                  </button>\n                  <div id=\"member-orders-empty\" class=\"portal-lock-note\">Loading your orders…</div>\n                  <div id=\"member-orders-list\" class=\"broadcast-list hidden\"></div>\n                </section>\n\n                <section class=\"portal-card portal-surface\" data-reveal>\n                  <div class=\"portal-card-head\">\n                    <p class=\"eyebrow\">Order details</p>\n                    <h3 class=\"brand-font\">Submit an order</h3>\n                  </div>\n                  <form id=\"order-form\" class=\"stack-form\">\n                    <label class=\"field\" for=\"order-name\">\n                      <span class=\"field-label\">Your name</span>\n                      <input\n                        id=\"order-name\"\n                        name=\"order-name\"\n                        class=\"input\"\n                        type=\"text\"\n                        placeholder=\"Your name\"\n                        required\n                      />\n                    </label>\n                    <label class=\"field\" for=\"order-phone\">\n                      <span class=\"field-label\">Phone</span>\n                      <input\n                        id=\"order-phone\"\n                        name=\"order-phone\"\n                        class=\"input\"\n                        type=\"tel\"\n                        autocomplete=\"tel\"\n                        placeholder=\"Phone number\"\n                      />\n                    </label>\n                    <label class=\"field\" for=\"order-state\">\n                      <span class=\"field-label\">State</span>\n                      <select id=\"order-state\" name=\"order-state\" class=\"input\">\n                        <option value=\"SA\" selected>SA</option>\n                        <option value=\"VIC\">VIC</option>\n                        <option value=\"NSW\">NSW</option>\n                        <option value=\"QLD\">QLD</option>\n                        <option value=\"WA\">WA</option>\n                        <option value=\"TAS\">TAS</option>\n                        <option value=\"NT\">NT</option>\n                        <option value=\"ACT\">ACT</option>\n                        <option value=\"OTHER\">Other</option>\n                      </select>\n                    </label>\n                    <label class=\"field\" for=\"order-notes\">\n                      <span class=\"field-label\">Notes</span>\n                      <textarea\n                        id=\"order-notes\"\n                        name=\"order-notes\"\n                        class=\"input textarea\"\n                        placeholder=\"Pickup, delivery, or other notes\"\n                      ></textarea>\n                    </label>\n                    <button\n                      id=\"submit-order-btn\"\n                      class=\"button button-primary button-full\"\n                      type=\"submit\"\n                    >\n                      Submit order\n                    </button>\n                    <p class=\"portal-card-copy portal-card-copy-tight\">\n                      Orders are saved to your member account so the club can confirm sizing,\n                      pickup, and delivery details. When email is configured, you will receive a\n                      confirmation at your sign-in address after submit.\n                    </p>\n                  </form>\n                </section>\n              </aside>\n            </div>\n          </section>\n\n          <section id=\"pane-account\" class=\"portal-pane hidden\" data-reveal>\n            <div class=\"account-grid\">\n              <section class=\"portal-card portal-surface\" data-reveal>\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Password</p>\n                  <h3 class=\"brand-font\">Save a new password</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  If you just came in from a recovery email, set the new password here while signed\n                  in.\n                </p>\n                <form id=\"set-password-form\" class=\"stack-form\">\n                  <input\n                    id=\"password-username\"\n                    class=\"visually-hidden\"\n                    type=\"email\"\n                    autocomplete=\"username\"\n                    tabindex=\"-1\"\n                    aria-hidden=\"true\"\n                  />\n                  <label class=\"field\" for=\"new-password\">\n                    <span class=\"field-label\">New password</span>\n                    <input\n                      id=\"new-password\"\n                      name=\"new-password\"\n                      class=\"input\"\n                      type=\"password\"\n                      autocomplete=\"new-password\"\n                      placeholder=\"Enter new password\"\n                      required\n                      minlength=\"8\"\n                    />\n                  </label>\n                  <label class=\"field\" for=\"confirm-password\">\n                    <span class=\"field-label\">Confirm password</span>\n                    <input\n                      id=\"confirm-password\"\n                      name=\"confirm-password\"\n                      class=\"input\"\n                      type=\"password\"\n                      autocomplete=\"new-password\"\n                      placeholder=\"Confirm new password\"\n                      required\n                      minlength=\"8\"\n                    />\n                  </label>\n                  <button\n                    id=\"set-password-btn\"\n                    class=\"button button-secondary button-full\"\n                    type=\"submit\"\n                  >\n                    Save password\n                  </button>\n                </form>\n              </section>\n\n              <section class=\"portal-card portal-surface\" data-reveal>\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Member profile</p>\n                  <h3 class=\"brand-font\">Notification preferences</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Keep your contact details current so event notices and chapter updates can reach\n                  you.\n                </p>\n                <div id=\"profile-status\" class=\"profile-status\">Loading your profile...</div>\n                <div id=\"profile-meta\" class=\"profile-meta hidden\"></div>\n                <form id=\"member-profile-form\" class=\"stack-form\">\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"profile-full-name\">\n                      <span class=\"field-label\">Display name</span>\n                      <input\n                        id=\"profile-full-name\"\n                        name=\"profile-full-name\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"120\"\n                        placeholder=\"Your name\"\n                      />\n                    </label>\n                    <label class=\"field\" for=\"profile-phone\">\n                      <span class=\"field-label\">Phone</span>\n                      <input\n                        id=\"profile-phone\"\n                        name=\"profile-phone\"\n                        class=\"input\"\n                        type=\"tel\"\n                        autocomplete=\"tel\"\n                        placeholder=\"Mobile number\"\n                      />\n                    </label>\n                  </div>\n                  <label class=\"field\" for=\"profile-email\">\n                    <span class=\"field-label\">Email</span>\n                    <input\n                      id=\"profile-email\"\n                      name=\"profile-email\"\n                      class=\"input\"\n                      type=\"email\"\n                      disabled\n                    />\n                  </label>\n                  <div class=\"field-row\">\n                    <label class=\"checkbox-row\" for=\"profile-notify-email\">\n                      <input\n                        id=\"profile-notify-email\"\n                        name=\"profile-notify-email\"\n                        type=\"checkbox\"\n                        checked\n                      />\n                      <span>Email event updates</span>\n                    </label>\n                    <label class=\"checkbox-row\" for=\"profile-notify-sms\">\n                      <input id=\"profile-notify-sms\" name=\"profile-notify-sms\" type=\"checkbox\" />\n                      <span>SMS event updates</span>\n                    </label>\n                  </div>\n                  <button\n                    id=\"save-profile-btn\"\n                    class=\"button button-primary button-full\"\n                    type=\"submit\"\n                  >\n                    Save profile\n                  </button>\n                  <p class=\"portal-card-copy portal-card-copy-tight\">\n                    Keep this up to date so the club can reach you quickly when plans change.\n                  </p>\n                </form>\n              </section>\n            </div>\n          </section>\n\n          <section id=\"pane-chat\" class=\"portal-pane hidden\" data-reveal>\n            <section class=\"portal-chat portal-surface\">\n              <div class=\"portal-chat-head\">\n                <div>\n                  <p class=\"eyebrow\">Members chat</p>\n                  <h3 class=\"brand-font\">Chapter chat board</h3>\n                </div>\n                <button id=\"chat-refresh-btn\" class=\"button button-secondary\" type=\"button\">\n                  Refresh chat\n                </button>\n              </div>\n\n              <p id=\"chat-status\" class=\"portal-chat-status\">\n                Signed-in members can post updates, quick notices, and club chatter here.\n              </p>\n\n              <div id=\"chat-empty\" class=\"portal-chat-empty hidden\">\n                No messages yet. Be the first member to start the conversation.\n              </div>\n\n              <div id=\"chat-list\" class=\"portal-chat-list\"></div>\n\n              <form id=\"chat-form\" class=\"portal-chat-form\">\n                <label class=\"field\" for=\"chat-display-name\">\n                  <span class=\"field-label\">Display name</span>\n                  <input\n                    id=\"chat-display-name\"\n                    name=\"chat-display-name\"\n                    class=\"input\"\n                    type=\"text\"\n                    maxlength=\"80\"\n                    placeholder=\"How your name should appear\"\n                    required\n                  />\n                </label>\n\n                <label class=\"field\" for=\"chat-message\">\n                  <span class=\"field-label\">Message</span>\n                  <textarea\n                    id=\"chat-message\"\n                    name=\"chat-message\"\n                    class=\"input textarea\"\n                    maxlength=\"500\"\n                    placeholder=\"Post a member update, ride note, or quick announcement\"\n                    required\n                  ></textarea>\n                </label>\n\n                <div class=\"portal-chat-actions\">\n                  <p class=\"portal-card-copy portal-card-copy-tight\">\n                    Messages are visible to signed-in members only. Use this for club chat, notices,\n                    and quick coordination.\n                  </p>\n                  <button id=\"chat-send-btn\" class=\"button button-primary\" type=\"submit\">\n                    Send message\n                  </button>\n                </div>\n              </form>\n            </section>\n          </section>\n\n          <section id=\"pane-admin\" class=\"portal-pane hidden\" data-reveal>\n            <div class=\"admin-stack\">\n              <div class=\"admin-section-toolbar portal-surface\">\n                <div class=\"admin-section-picker-wrap\">\n                  <label class=\"field admin-section-picker-field\" for=\"admin-section-picker\">\n                    <span class=\"field-label\">Admin area</span>\n                    <select id=\"admin-section-picker\" class=\"input admin-section-picker\" name=\"admin-section-picker\">\n                      <option value=\"overview\">Overview</option>\n                      <option value=\"orders\">Orders</option>\n                      <option value=\"members\">Members</option>\n                      <option value=\"merch\">Merch</option>\n                      <option value=\"website\">Website</option>\n                      <option value=\"notices\">Notices</option>\n                      <option value=\"invites\">Invites</option>\n                    </select>\n                  </label>\n                </div>\n                <nav class=\"admin-section-tabs\" role=\"tablist\" aria-label=\"Admin tools\">\n                  <button\n                    type=\"button\"\n                    role=\"tab\"\n                    class=\"admin-section-tab is-active\"\n                    data-admin-section-tab=\"overview\"\n                    aria-selected=\"true\"\n                  >\n                    Overview\n                  </button>\n                  <button type=\"button\" role=\"tab\" class=\"admin-section-tab\" data-admin-section-tab=\"orders\" aria-selected=\"false\">\n                    Orders\n                  </button>\n                  <button type=\"button\" role=\"tab\" class=\"admin-section-tab\" data-admin-section-tab=\"members\" aria-selected=\"false\">\n                    Members\n                  </button>\n                  <button type=\"button\" role=\"tab\" class=\"admin-section-tab\" data-admin-section-tab=\"merch\" aria-selected=\"false\">\n                    Merch\n                  </button>\n                  <button type=\"button\" role=\"tab\" class=\"admin-section-tab\" data-admin-section-tab=\"website\" aria-selected=\"false\">\n                    Website\n                  </button>\n                  <button type=\"button\" role=\"tab\" class=\"admin-section-tab\" data-admin-section-tab=\"notices\" aria-selected=\"false\">\n                    Notices\n                  </button>\n                  <button type=\"button\" role=\"tab\" class=\"admin-section-tab\" data-admin-section-tab=\"invites\" aria-selected=\"false\">\n                    Invites\n                  </button>\n                </nav>\n              </div>\n\n              <section\n                id=\"admin-overview\"\n                class=\"portal-card portal-surface admin-section-panel is-active\"\n                data-admin-section=\"overview\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Admin dashboard</p>\n                  <h3 class=\"brand-font\">Control panel readiness</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Check what is live before sending notices, editing the public website, or running\n                  the members shop.\n                </p>\n                <div id=\"admin-dashboard-metrics\" class=\"broadcast-metrics\"></div>\n                <div class=\"admin-dashboard-actions\" role=\"group\" aria-label=\"Admin quick jumps\">\n                  <button\n                    class=\"button button-secondary button-small admin-dashboard-action\"\n                    type=\"button\"\n                    data-admin-target=\"admin-members\"\n                    aria-controls=\"admin-members\"\n                  >\n                    Open members\n                  </button>\n                  <button\n                    class=\"button button-secondary button-small admin-dashboard-action\"\n                    type=\"button\"\n                    data-admin-target=\"admin-merch-manager\"\n                    aria-controls=\"admin-merch-manager\"\n                  >\n                    Open merch\n                  </button>\n                  <button\n                    class=\"button button-secondary button-small admin-dashboard-action\"\n                    type=\"button\"\n                    data-admin-target=\"admin-site-content\"\n                    aria-controls=\"admin-site-content\"\n                  >\n                    Open website\n                  </button>\n                  <button\n                    class=\"button button-secondary button-small admin-dashboard-action\"\n                    type=\"button\"\n                    data-admin-target=\"admin-broadcasts\"\n                    aria-controls=\"admin-broadcasts\"\n                  >\n                    Open notices\n                  </button>\n                  <button\n                    class=\"button button-secondary button-small admin-dashboard-action\"\n                    type=\"button\"\n                    data-admin-target=\"admin-invites\"\n                    aria-controls=\"admin-invites\"\n                  >\n                    Open invites\n                  </button>\n                  <button\n                    class=\"button button-secondary button-small admin-dashboard-action\"\n                    type=\"button\"\n                    data-admin-target=\"admin-orders\"\n                    aria-controls=\"admin-orders\"\n                  >\n                    Open orders\n                  </button>\n                </div>\n                <div id=\"admin-dashboard-grid\" class=\"admin-status-grid\"></div>\n                <div id=\"admin-dashboard-next\" class=\"portal-lock-note\">\n                  Sign in with the admin account to see what is ready and what still needs setup.\n                </div>\n              </section>\n\n              <section\n                id=\"admin-orders\"\n                class=\"portal-card portal-surface admin-jump-target admin-section-panel\"\n                data-admin-section=\"orders\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Drop fulfillment</p>\n                  <h3 class=\"brand-font\">Member orders</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Review cart submissions from the current drop. Update status as you confirm, pack,\n                  or ship.\n                </p>\n                <div class=\"member-directory-toolbar\">\n                  <button\n                    id=\"refresh-admin-orders-btn\"\n                    class=\"button button-secondary button-small\"\n                    type=\"button\"\n                  >\n                    Refresh orders\n                  </button>\n                </div>\n                <p id=\"admin-orders-status\" class=\"portal-lock-note hidden\"></p>\n                <div id=\"admin-orders-empty\" class=\"portal-lock-note\">\n                  Loading orders…\n                </div>\n                <div id=\"admin-orders-list\" class=\"hidden\"></div>\n              </section>\n\n              <section\n                id=\"admin-members\"\n                class=\"portal-card portal-surface admin-jump-target admin-section-panel\"\n                data-admin-section=\"members\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Member directory</p>\n                  <h3 class=\"brand-font\">Approve members and manage admin access</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  This is the admin home for member approval and backup-admin coverage. Use it to\n                  approve members, promote a second admin, and keep the primary admin protected from\n                  accidental lockouts.\n                </p>\n                <div class=\"member-directory-toolbar\">\n                  <label class=\"field\" for=\"member-directory-search\">\n                    <span class=\"field-label\">Search members</span>\n                    <input\n                      id=\"member-directory-search\"\n                      name=\"member-directory-search\"\n                      class=\"input\"\n                      type=\"search\"\n                      placeholder=\"Search by name, email, or phone\"\n                    />\n                  </label>\n                  <label class=\"field\" for=\"member-directory-filter\">\n                    <span class=\"field-label\">Filter</span>\n                    <select id=\"member-directory-filter\" name=\"member-directory-filter\" class=\"input\">\n                      <option value=\"all\">All members</option>\n                      <option value=\"approved\">Approved only</option>\n                      <option value=\"pending\">Pending approval</option>\n                      <option value=\"admins\">Admins only</option>\n                    </select>\n                  </label>\n                  <div class=\"field member-directory-toolbar-action\">\n                    <span class=\"field-label\">Refresh</span>\n                    <button\n                      id=\"refresh-member-directory-btn\"\n                      class=\"button button-secondary\"\n                      type=\"button\"\n                    >\n                      Refresh members\n                    </button>\n                  </div>\n                </div>\n                <div id=\"member-directory-status\" class=\"broadcast-status\">\n                  Member directory access will load here once the admin account is ready.\n                </div>\n                <div id=\"member-directory-summary\" class=\"broadcast-metrics hidden\"></div>\n                <div id=\"member-directory-empty\" class=\"portal-lock-note\">\n                  Member records will appear here after the admin directory loads.\n                </div>\n                <div id=\"member-directory-list\" class=\"broadcast-list hidden\"></div>\n              </section>\n\n              <section\n                id=\"admin-merch-manager\"\n                class=\"portal-card portal-surface admin-jump-target admin-section-panel\"\n                data-admin-section=\"merch\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Merch manager</p>\n                  <h3 class=\"brand-font\">Add, hide, and update merch</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Run the members shop from here. Add new items, update prices and images, hide old\n                  stock from the shop, or delete products you no longer need.\n                </p>\n                <div class=\"admin-merch-layout\">\n                  <form id=\"merch-admin-form\" class=\"stack-form\">\n                    <input id=\"merch-admin-id\" type=\"hidden\" />\n                    <div class=\"field-row\">\n                      <label class=\"field\" for=\"merch-admin-name\">\n                        <span class=\"field-label\">Item name</span>\n                        <input\n                          id=\"merch-admin-name\"\n                          name=\"merch-admin-name\"\n                          class=\"input\"\n                          type=\"text\"\n                          maxlength=\"160\"\n                          placeholder=\"BLFSC Tee\"\n                        />\n                      </label>\n                      <label class=\"field\" for=\"merch-admin-category\">\n                        <span class=\"field-label\">Category</span>\n                        <select id=\"merch-admin-category\" name=\"merch-admin-category\" class=\"input\">\n                          <option value=\"shirts\">Shirts</option>\n                          <option value=\"outerwear\">Outerwear</option>\n                          <option value=\"pants\">Pants</option>\n                          <option value=\"accessories\">Accessories</option>\n                          <option value=\"other\">Other</option>\n                        </select>\n                      </label>\n                    </div>\n                    <div class=\"field-row\">\n                      <label class=\"field\" for=\"merch-admin-price\">\n                        <span class=\"field-label\">Price</span>\n                        <input\n                          id=\"merch-admin-price\"\n                          name=\"merch-admin-price\"\n                          class=\"input\"\n                          type=\"number\"\n                          min=\"0\"\n                          step=\"0.01\"\n                          placeholder=\"45.00\"\n                        />\n                      </label>\n                      <label class=\"field\" for=\"merch-admin-image-url\">\n                        <span class=\"field-label\">Image path or URL</span>\n                        <input\n                          id=\"merch-admin-image-url\"\n                          name=\"merch-admin-image-url\"\n                          class=\"input\"\n                          type=\"text\"\n                          maxlength=\"500\"\n                        placeholder=\"/images/blfsc-tee.jpeg\"\n                        />\n                      </label>\n                    </div>\n                    <div class=\"field-row\">\n                      <div class=\"field\">\n                        <span class=\"field-label\">Upload image</span>\n                        <div\n                          id=\"merch-admin-dropzone\"\n                          class=\"admin-merch-dropzone\"\n                          tabindex=\"0\"\n                          role=\"button\"\n                          aria-controls=\"merch-admin-image-file\"\n                          aria-describedby=\"merch-admin-dropzone-copy\"\n                        >\n                          <strong id=\"merch-admin-image-file-name\"\n                            >Drop image here or tap to choose</strong\n                          >\n                          <p id=\"merch-admin-dropzone-copy\">\n                            JPG, PNG, WEBP, or GIF. Images are cropped square and resized\n                            automatically before upload.\n                          </p>\n                          <input\n                            id=\"merch-admin-image-file\"\n                            name=\"merch-admin-image-file\"\n                            class=\"visually-hidden\"\n                            type=\"file\"\n                            accept=\"image/png,image/jpeg,image/webp,image/gif\"\n                          />\n                        </div>\n                      </div>\n                      <div class=\"field\">\n                        <span class=\"field-label\">Image preview</span>\n                        <div class=\"admin-merch-preview\">\n                          <img\n                            id=\"merch-admin-preview\"\n                            class=\"admin-merch-preview-image hidden\"\n                            alt=\"Merch preview\"\n                          />\n                          <div\n                            id=\"merch-admin-preview-empty\"\n                            class=\"portal-lock-note admin-merch-preview-empty\"\n                          >\n                            Pick an image to preview it here. If you upload a file, it will be\n                            stored automatically when you save the merch item.\n                          </div>\n                        </div>\n                      </div>\n                    </div>\n                    <label class=\"field\" for=\"merch-admin-description\">\n                      <span class=\"field-label\">Description</span>\n                      <textarea\n                        id=\"merch-admin-description\"\n                        name=\"merch-admin-description\"\n                        class=\"input textarea\"\n                        maxlength=\"500\"\n                        placeholder=\"Short merch description for members\"\n                      ></textarea>\n                    </label>\n                    <div class=\"field-row\">\n                      <label class=\"checkbox-row\" for=\"merch-admin-has-sizes\">\n                        <input\n                          id=\"merch-admin-has-sizes\"\n                          name=\"merch-admin-has-sizes\"\n                          type=\"checkbox\"\n                        />\n                        <span>This item uses size selection</span>\n                      </label>\n                      <label class=\"checkbox-row\" for=\"merch-admin-active\">\n                        <input\n                          id=\"merch-admin-active\"\n                          name=\"merch-admin-active\"\n                          type=\"checkbox\"\n                          checked\n                        />\n                        <span>Show this item live in the members shop</span>\n                      </label>\n                    </div>\n                    <div class=\"portal-lock-note\">\n                      Hidden items stay saved in the merch manager but disappear from the members\n                      shop. You can still paste an image URL if you want, but the quickest option is\n                      to pick a file and save.\n                    </div>\n                    <div class=\"invite-toolbar\">\n                      <button id=\"save-merch-btn\" class=\"button button-primary\" type=\"submit\">\n                        Add merch item\n                      </button>\n                      <button\n                        id=\"clear-merch-image-btn\"\n                        class=\"button button-secondary\"\n                        type=\"button\"\n                      >\n                        Clear selected image\n                      </button>\n                      <button\n                        id=\"reset-merch-form-btn\"\n                        class=\"button button-secondary\"\n                        type=\"button\"\n                      >\n                        Clear form\n                      </button>\n                    </div>\n                    <div id=\"merch-admin-status\" class=\"broadcast-status\">\n                      Merch manager will load here for the admin account.\n                    </div>\n                  </form>\n\n                  <div class=\"admin-merch-panel\">\n                    <div id=\"merch-admin-summary\" class=\"broadcast-metrics hidden\"></div>\n                    <div id=\"merch-admin-empty\" class=\"portal-lock-note\">\n                      Your merch list will appear here when admin access is active.\n                    </div>\n                    <div id=\"merch-admin-list\" class=\"broadcast-list hidden\"></div>\n                  </div>\n                </div>\n              </section>\n\n              <section\n                id=\"admin-site-content\"\n                class=\"portal-card portal-surface admin-jump-target admin-section-panel\"\n                data-admin-section=\"website\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Website content</p>\n                  <h3 class=\"brand-font\">Edit the public website</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Update the main BLFSC website here without touching code. These fields feed\n                  blfsc.com so you can tune the homepage, about copy, contact details, and footer\n                  messaging from the admin account.\n                </p>\n                <form id=\"site-content-form\" class=\"stack-form\">\n                  <div class=\"field-row\">\n                    <div class=\"field\">\n                      <span class=\"field-label\">Sitewide announcement bar</span>\n                      <label\n                        class=\"checkbox-row checkbox-row-inline\"\n                        for=\"site-announcement-enabled\"\n                      >\n                        <input\n                          id=\"site-announcement-enabled\"\n                          name=\"site-announcement-enabled\"\n                          type=\"checkbox\"\n                        />\n                        <span>Show a sitewide notice at the top of every public page</span>\n                      </label>\n                    </div>\n                    <label class=\"field\" for=\"site-announcement-title\">\n                      <span class=\"field-label\">Announcement label</span>\n                      <input\n                        id=\"site-announcement-title\"\n                        name=\"site-announcement-title\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"80\"\n                        placeholder=\"Club notice\"\n                      />\n                    </label>\n                  </div>\n                  <label class=\"field\" for=\"site-announcement-message\">\n                    <span class=\"field-label\">Announcement message</span>\n                    <textarea\n                      id=\"site-announcement-message\"\n                      name=\"site-announcement-message\"\n                      class=\"input textarea\"\n                      maxlength=\"220\"\n                      placeholder=\"Top-bar message for urgent ride updates or public notices\"\n                    ></textarea>\n                  </label>\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"site-announcement-link-label\">\n                      <span class=\"field-label\">Announcement button label</span>\n                      <input\n                        id=\"site-announcement-link-label\"\n                        name=\"site-announcement-link-label\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"40\"\n                        placeholder=\"View events\"\n                      />\n                    </label>\n                    <label class=\"field\" for=\"site-announcement-link-href\">\n                      <span class=\"field-label\">Announcement button link</span>\n                      <input\n                        id=\"site-announcement-link-href\"\n                        name=\"site-announcement-link-href\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"200\"\n                        placeholder=\"/events\"\n                      />\n                    </label>\n                  </div>\n\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"site-hero-title\">\n                      <span class=\"field-label\">Hero title</span>\n                      <input\n                        id=\"site-hero-title\"\n                        name=\"site-hero-title\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"180\"\n                        placeholder=\"B.L.F. Social Club. Rides, meet-ups, and members-only merch.\"\n                      />\n                    </label>\n                    <label class=\"field\" for=\"site-hero-notice-title\">\n                      <span class=\"field-label\">Hero notice title</span>\n                      <input\n                        id=\"site-hero-notice-title\"\n                        name=\"site-hero-notice-title\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"120\"\n                        placeholder=\"Next public ride window\"\n                      />\n                    </label>\n                  </div>\n                  <label class=\"field\" for=\"site-hero-description\">\n                    <span class=\"field-label\">Hero description</span>\n                    <textarea\n                      id=\"site-hero-description\"\n                      name=\"site-hero-description\"\n                      class=\"input textarea\"\n                      maxlength=\"500\"\n                      placeholder=\"Short public intro for the homepage hero\"\n                    ></textarea>\n                  </label>\n                  <label class=\"field\" for=\"site-hero-notice-copy\">\n                    <span class=\"field-label\">Hero notice copy</span>\n                    <textarea\n                      id=\"site-hero-notice-copy\"\n                      name=\"site-hero-notice-copy\"\n                      class=\"input textarea\"\n                      maxlength=\"320\"\n                      placeholder=\"Short ride notice, next meet-up, or pinned message\"\n                    ></textarea>\n                  </label>\n\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"site-story-title\">\n                      <span class=\"field-label\">Story section title</span>\n                      <input\n                        id=\"site-story-title\"\n                        name=\"site-story-title\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"160\"\n                        placeholder=\"Built around the ride, the meet-up, and the people behind it.\"\n                      />\n                    </label>\n                    <div class=\"portal-lock-note\">\n                      Changes are saved to Supabase right away and the live public site refreshes\n                      within about a minute.\n                    </div>\n                  </div>\n                  <label class=\"field\" for=\"site-story-paragraph-one\">\n                    <span class=\"field-label\">Story paragraph one</span>\n                    <textarea\n                      id=\"site-story-paragraph-one\"\n                      name=\"site-story-paragraph-one\"\n                      class=\"input textarea\"\n                      maxlength=\"500\"\n                      placeholder=\"First about paragraph\"\n                    ></textarea>\n                  </label>\n                  <label class=\"field\" for=\"site-story-paragraph-two\">\n                    <span class=\"field-label\">Story paragraph two</span>\n                    <textarea\n                      id=\"site-story-paragraph-two\"\n                      name=\"site-story-paragraph-two\"\n                      class=\"input textarea\"\n                      maxlength=\"500\"\n                      placeholder=\"Second about paragraph\"\n                    ></textarea>\n                  </label>\n\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"site-contact-email\">\n                      <span class=\"field-label\">Contact email</span>\n                      <input\n                        id=\"site-contact-email\"\n                        name=\"site-contact-email\"\n                        class=\"input\"\n                        type=\"email\"\n                        placeholder=\"club@example.com\"\n                      />\n                    </label>\n                    <label class=\"field\" for=\"site-contact-phone\">\n                      <span class=\"field-label\">Contact phone</span>\n                      <input\n                        id=\"site-contact-phone\"\n                        name=\"site-contact-phone\"\n                        class=\"input\"\n                        type=\"text\"\n                        maxlength=\"40\"\n                        placeholder=\"0417 000 000\"\n                      />\n                    </label>\n                  </div>\n\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"site-instagram-url\">\n                      <span class=\"field-label\">Instagram URL</span>\n                      <input\n                        id=\"site-instagram-url\"\n                        name=\"site-instagram-url\"\n                        class=\"input\"\n                        type=\"url\"\n                        placeholder=\"https://instagram.com/yourclub\"\n                      />\n                    </label>\n                    <label class=\"field\" for=\"site-facebook-url\">\n                      <span class=\"field-label\">Facebook URL</span>\n                      <input\n                        id=\"site-facebook-url\"\n                        name=\"site-facebook-url\"\n                        class=\"input\"\n                        type=\"url\"\n                        placeholder=\"https://facebook.com/yourclub\"\n                      />\n                    </label>\n                  </div>\n                  <label class=\"field\" for=\"site-tiktok-url\">\n                    <span class=\"field-label\">TikTok URL</span>\n                    <input\n                      id=\"site-tiktok-url\"\n                      name=\"site-tiktok-url\"\n                      class=\"input\"\n                      type=\"url\"\n                      placeholder=\"https://tiktok.com/@yourclub\"\n                    />\n                  </label>\n\n                  <label class=\"field\" for=\"site-footer-title\">\n                    <span class=\"field-label\">Footer title</span>\n                    <input\n                      id=\"site-footer-title\"\n                      name=\"site-footer-title\"\n                      class=\"input\"\n                      type=\"text\"\n                      maxlength=\"180\"\n                      placeholder=\"Footer headline\"\n                    />\n                  </label>\n                  <label class=\"field\" for=\"site-footer-copy\">\n                    <span class=\"field-label\">Footer copy</span>\n                    <textarea\n                      id=\"site-footer-copy\"\n                      name=\"site-footer-copy\"\n                      class=\"input textarea\"\n                      maxlength=\"400\"\n                      placeholder=\"Footer support copy\"\n                    ></textarea>\n                  </label>\n                  <label class=\"field\" for=\"site-footer-note\">\n                    <span class=\"field-label\">Footer note</span>\n                    <textarea\n                      id=\"site-footer-note\"\n                      name=\"site-footer-note\"\n                      class=\"input textarea\"\n                      maxlength=\"280\"\n                      placeholder=\"Short footer note\"\n                    ></textarea>\n                  </label>\n\n                  <div class=\"portal-lock-note\">\n                    Advanced website JSON controls the rest of the live public site from this same\n                    admin panel, including home-page cards, the public events list, about/contact\n                    sections, merch-page copy, and privacy/terms text. The simple fields above still\n                    own announcement, hero, story, contact details, and footer settings.\n                  </div>\n                  <label class=\"field\" for=\"site-advanced-json\">\n                    <span class=\"field-label\">Advanced website JSON</span>\n                    <textarea\n                      id=\"site-advanced-json\"\n                      name=\"site-advanced-json\"\n                      class=\"input textarea\"\n                      rows=\"18\"\n                      spellcheck=\"false\"\n                      placeholder='{\"home\": {\"quickLinks\": []}, \"events\": []}'\n                    ></textarea>\n                  </label>\n\n                  <div class=\"invite-toolbar\">\n                    <button id=\"save-site-content-btn\" class=\"button button-primary\" type=\"submit\">\n                      Save website content\n                    </button>\n                    <button\n                      id=\"reset-site-content-btn\"\n                      class=\"button button-secondary\"\n                      type=\"button\"\n                    >\n                      Load defaults\n                    </button>\n                    <button\n                      id=\"copy-website-link-btn\"\n                      class=\"button button-secondary\"\n                      type=\"button\"\n                    >\n                      Copy website link\n                    </button>\n                    <a\n                      class=\"button button-secondary\"\n                      href=\"__PUBLIC_SITE_URL__\"\n                      target=\"_blank\"\n                      rel=\"noreferrer\"\n                      >Open website</a\n                    >\n                  </div>\n                  <div id=\"site-content-status\" class=\"broadcast-status\">\n                    Website content controls will load here once the admin account and site content\n                    table are ready.\n                  </div>\n                </form>\n              </section>\n\n              <div class=\"admin-section-panel\" data-admin-section=\"notices\">\n              <section\n                id=\"admin-broadcasts\"\n                class=\"portal-card portal-surface admin-jump-target\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Admin only</p>\n                  <h3 class=\"brand-font\">Broadcast an event notice</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Send a message to approved members by email, SMS, or both. This pane uses the\n                  notification tables and edge function if they are configured.\n                </p>\n                <div id=\"admin-access-note\" class=\"portal-lock-note hidden\"></div>\n                <form id=\"member-broadcast-form\" class=\"stack-form\">\n                  <label class=\"field\" for=\"broadcast-subject\">\n                    <span class=\"field-label\">Subject</span>\n                    <input\n                      id=\"broadcast-subject\"\n                      name=\"broadcast-subject\"\n                      class=\"input\"\n                      type=\"text\"\n                      maxlength=\"160\"\n                      placeholder=\"Event reminder, route change, and so on\"\n                    />\n                  </label>\n                  <label class=\"field\" for=\"broadcast-message\">\n                    <span class=\"field-label\">Message</span>\n                    <textarea\n                      id=\"broadcast-message\"\n                      name=\"broadcast-message\"\n                      class=\"input textarea\"\n                      maxlength=\"2000\"\n                      placeholder=\"Write the notice you want to send to members\"\n                    ></textarea>\n                  </label>\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"broadcast-audience\">\n                      <span class=\"field-label\">Audience</span>\n                      <select id=\"broadcast-audience\" name=\"broadcast-audience\" class=\"input\">\n                        <option value=\"approved_members\" selected>Approved members</option>\n                        <option value=\"all_members\">All members</option>\n                      </select>\n                    </label>\n                    <div class=\"field\">\n                      <span class=\"field-label\">Send mode</span>\n                      <label class=\"checkbox-row checkbox-row-inline\" for=\"broadcast-dry-run\">\n                        <input id=\"broadcast-dry-run\" name=\"broadcast-dry-run\" type=\"checkbox\" />\n                        <span>Draft only</span>\n                      </label>\n                    </div>\n                  </div>\n                  <div class=\"broadcast-channel-row\">\n                    <label class=\"checkbox-row\" for=\"broadcast-email\">\n                      <input id=\"broadcast-email\" name=\"broadcast-email\" type=\"checkbox\" checked />\n                      <span>Email</span>\n                    </label>\n                    <label class=\"checkbox-row\" for=\"broadcast-sms\">\n                      <input id=\"broadcast-sms\" name=\"broadcast-sms\" type=\"checkbox\" />\n                      <span>SMS</span>\n                    </label>\n                  </div>\n                  <button\n                    id=\"send-broadcast-btn\"\n                    class=\"button button-primary button-full\"\n                    type=\"submit\"\n                  >\n                    Send notification\n                  </button>\n                  <div id=\"broadcast-status\" class=\"broadcast-status\">\n                    Drafts work immediately. Live delivery needs an email provider like Resend or\n                    SMTP, and SMS needs Twilio.\n                  </div>\n                </form>\n              </section>\n\n              <section class=\"portal-card portal-surface\" data-reveal>\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">History</p>\n                  <h3 class=\"brand-font\">Recent broadcasts</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Review queued, draft, and sent notices here when the notification tables are\n                  available.\n                </p>\n                <div id=\"broadcast-metrics\" class=\"broadcast-metrics hidden\"></div>\n                <div id=\"broadcast-history-empty\" class=\"portal-lock-note\">\n                  Broadcast history will appear here once the notification tables are deployed.\n                </div>\n                <div id=\"broadcast-history-list\" class=\"broadcast-list hidden\"></div>\n              </section>\n              </div>\n\n              <section\n                id=\"admin-invites\"\n                class=\"portal-card portal-surface admin-jump-target admin-section-panel\"\n                data-admin-section=\"invites\"\n                data-reveal\n              >\n                <div class=\"portal-card-head\">\n                  <p class=\"eyebrow\">Member invites</p>\n                  <h3 class=\"brand-font\">Generate one-time invite links</h3>\n                </div>\n                <p class=\"portal-card-copy\">\n                  Paste one email per line. If you also have a mobile number, paste it on the\n                  matching line and the portal will text the same invite link to that member. Email\n                  is still the account identity for the Supabase invite.\n                </p>\n                <form id=\"member-invite-form\" class=\"stack-form\">\n                  <label class=\"field\" for=\"invite-emails\">\n                    <span class=\"field-label\">Member emails</span>\n                    <textarea\n                      id=\"invite-emails\"\n                      name=\"invite-emails\"\n                      class=\"input textarea\"\n                      placeholder=\"member1@example.com&#10;member2@example.com\"\n                    ></textarea>\n                  </label>\n                  <label class=\"field\" for=\"invite-phones\">\n                    <span class=\"field-label\">Phone numbers, optional</span>\n                    <textarea\n                      id=\"invite-phones\"\n                      name=\"invite-phones\"\n                      class=\"input textarea\"\n                      placeholder=\"0412 345 678&#10;0417 555 121\"\n                    ></textarea>\n                  </label>\n                  <div class=\"field-row\">\n                    <label class=\"field\" for=\"invite-redirect\">\n                      <span class=\"field-label\">Invite redirect</span>\n                      <input\n                        id=\"invite-redirect\"\n                        name=\"invite-redirect\"\n                        class=\"input\"\n                        type=\"url\"\n                        placeholder=\"__PORTAL_URL__\"\n                      />\n                    </label>\n                    <div class=\"field\">\n                      <span class=\"field-label\">How it works</span>\n                      <div class=\"portal-lock-note\">\n                        Supabase sends an invitation email to each new address (configure Auth email\n                        or SMTP in your project). If you add a matching phone and Twilio is set up,\n                        the portal texts the invite link as well.\n                      </div>\n                    </div>\n                  </div>\n                  <div class=\"invite-toolbar\">\n                    <button\n                      id=\"generate-invite-links-btn\"\n                      class=\"button button-primary\"\n                      type=\"submit\"\n                    >\n                      Send invitations\n                    </button>\n                    <button\n                      id=\"download-invite-links-btn\"\n                      class=\"button button-secondary\"\n                      type=\"button\"\n                      disabled\n                    >\n                      Download CSV\n                    </button>\n                  </div>\n                  <div id=\"invite-links-status\" class=\"broadcast-status\">\n                    Results and delivery status will appear here once the admin account and invite\n                    function are configured.\n                  </div>\n                </form>\n                <div id=\"invite-results-empty\" class=\"portal-lock-note\">\n                  Invitation results will appear here after you run the tool.\n                </div>\n                <div id=\"invite-results-list\" class=\"broadcast-list hidden\"></div>\n              </section>\n            </div>\n          </section>\n        </main>\n\n        <div id=\"cart-overlay\" class=\"cart-overlay hidden\"></div>\n\n        <aside\n          id=\"cart-drawer\"\n          class=\"cart-drawer hidden\"\n          aria-labelledby=\"cart-title\"\n          aria-modal=\"true\"\n          role=\"dialog\"\n        >\n          <div class=\"cart-drawer-inner\">\n            <div class=\"cart-drawer-head\">\n              <div>\n                <p class=\"eyebrow\">Order review</p>\n                <h3 id=\"cart-title\" class=\"brand-font\">Your cart</h3>\n                <p class=\"portal-card-copy portal-card-copy-tight\">\n                  Review quantities, sizes, and totals before submitting.\n                </p>\n              </div>\n              <button id=\"close-cart\" class=\"button button-secondary\" type=\"button\">Close</button>\n            </div>\n\n            <div id=\"cart-items\" class=\"cart-items\"></div>\n\n            <div class=\"cart-total-box\">\n              <span>Total</span>\n              <strong id=\"cart-total\">$0.00</strong>\n            </div>\n          </div>\n        </aside>\n\n        <div id=\"toast\" class=\"portal-toast hidden\" aria-live=\"polite\"></div>\n      </section>\n    </div>";
